function swap(a, b) {
  a = a + b;
  b = a - b;
  a = a - b;
  return [a, b];
}

function findMax(arr) {
  let max = arr[0];
  for (let i = 1; i < arr.length; i++) {
    if (arr[i] > max) max = arr[i];
  }
  return max;
}

function reverseStr(s) {
  let result = '';
  for (let i = s.length - 1; i >= 0; i--) result += s[i];
  return result;
}

function countOccurrences(arr, target) {
  let count = 0;
  for (let i = 0; i < arr.length; i++) {
    if (arr[i] === target) count++;
  }
  return count;
}

function fizzBuzz(n) {
  const result = [];
  for (let i = 1; i <= n; i++) {
    if (i % 15 === 0) result.push('FizzBuzz');
    else if (i % 3 === 0) result.push('Fizz');
    else if (i % 5 === 0) result.push('Buzz');
    else result.push(i);
  }
  return result;
}

function twoSum(nums, target) {
  for (let i = 0; i < nums.length; i++)
    for (let j = i + 1; j < nums.length; j++)
      if (nums[i] + nums[j] === target) return [i, j];
}

function sumArray(arr) {
  let sum = 0;
  for (let i = 0; i < arr.length; i++) sum += arr[i];
  return sum;
}

function countVowels(s) {
  const v = 'aeiou'; let c = 0;
  s = s.toLowerCase();
  for (let i = 0; i < s.length; i++) if (v.includes(s[i])) c++;
  return c;
}

function removeDuplicates(arr) {
  const result = [];
  for (let i = 0; i < arr.length; i++) {
    let found = false;
    for (let j = 0; j < result.length; j++)
      if (result[j] === arr[i]) { found = true; break; }
    if (!found) result.push(arr[i]);
  }
  return result;
}

function factorial(n) {
  if (n === 0) return 1;
  let r = 1;
  for (let i = 1; i <= n; i++) r *= i;
  return r;
}

function reverseInPlace(arr) {
  let l = 0, r = arr.length - 1;
  while (l < r) {
    const t = arr[l]; arr[l] = arr[r]; arr[r] = t;
    l++; r--;
  }
  return arr;
}

function isAnagram(s1, s2) {
  s1 = s1.toLowerCase(); s2 = s2.toLowerCase();
  if (s1.length !== s2.length) return false;
  const c = {};
  for (let i = 0; i < s1.length; i++) c[s1[i]] = (c[s1[i]]||0)+1;
  for (let i = 0; i < s2.length; i++) { if (!c[s2[i]]) return false; c[s2[i]]--; }
  return true;
}

function secondLargest(arr) {
  let f = -Infinity, s = -Infinity;
  for (let i = 0; i < arr.length; i++) {
    if (arr[i] > f) { s = f; f = arr[i]; }
    else if (arr[i] > s && arr[i] !== f) s = arr[i];
  }
  return s;
}

function capitalizeWords(s) {
  let r = '', cap = true;
  for (let i = 0; i < s.length; i++) {
    if (s[i] === ' ') { r += ' '; cap = true; }
    else if (cap) { r += s[i].toUpperCase(); cap = false; }
    else r += s[i];
  }
  return r;
}

function intersect(a, b) {
  const c = {};
  for (const x of a) c[x] = (c[x]||0)+1;
  const r = [];
  for (const x of b) { if (c[x] > 0) { r.push(x); c[x]--; } }
  return r;
}

function runningSum(arr) {
  const r = [arr[0]];
  for (let i = 1; i < arr.length; i++) r.push(r[i-1]+arr[i]);
  return r;
}

function missingNumber(nums) {
  const n = nums.length;
  let sum = 0;
  for (let i = 0; i < n; i++) sum += nums[i];
  return n*(n+1)/2 - sum;
}

function isPowerOfTwo(n) {
  if (n <= 0) return false;
  return (n & (n - 1)) === 0;
}

function rotateArray(arr, k) {
  k = k % arr.length;
  function rev(s,e) { while(s<e){const t=arr[s];arr[s]=arr[e];arr[e]=t;s++;e--;} }
  rev(0, arr.length-1); rev(0, k-1); rev(k, arr.length-1);
  return arr;
}

function compress(s) {
  let r = '', c = 1;
  for (let i = 0; i < s.length; i++) {
    if (i+1 < s.length && s[i] === s[i+1]) c++;
    else { r += s[i] + c; c = 1; }
  }
  return r.length < s.length ? r : s;
}
